const express = require('express');
const axios = require('axios');
const app = express();
const PORT = 3000;

// Middleware for API key authentication and logging
app.use((req, res, next) => {
  const apiKey = req.query.api_key;
  if (!apiKey) {
    return res.status(401).json({ error: 'API key is required' });
  }

  // Log the request details
  console.log(`Request: ${req.method} ${req.url} - API Key: ${apiKey}`);

  // Forward the API key in headers
  req.headers['x-api-key'] = apiKey;
  next();
});

// Example route to forward requests to a backend service
app.use('/service1', async (req, res) => {
  try {
    const response = await axios({
      method: req.method,
      url: `http://backend-service1.com${req.path}`,
      headers: req.headers,
      data: req.body
    });
    res.status(response.status).send(response.data);
  } catch (error) {
    res.status(error.response ? error.response.status : 500).send(error.message);
  }
});

// Start the API gateway
app.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
});